function TopBar({ theme, setTheme }) {
    return (
        <div className="topbar">
            <div className="topbar-right">
                <button className="login-btn">Login</button>

                <button
                    className="theme-btn"
                    onClick={() => setTheme(theme === "light" ? "dark" : "light")}
                >
                    {theme === "light" ? "🌙" : "☀️"}
                </button>
            </div>
        </div>
    );
}

export default TopBar;
